window.PHORGE_EXAMPLES = {
  "hello (default)": "package Main;\nimport Core.Console;\n\nfunction main() {\n    List<string> who = [\"world\", \"Phorge\"];\n    for (string w in who) {\n        Console.println(\"Hello, {w}!\");\n    }\n}\n",
  "bytes": "package Main;\n\n// M6 W0 — the `bytes` type: raw octet sequences distinct from UTF-8 `string`.\n// `b\"…\"` literals (with `\\xHH`), and the `Core.Bytes` interop module.\nimport Core.Console;\nimport Core.Bytes;\n\nfunction main() {\n  // fromString + len (BYTE count) + toString round-trip.\n  bytes hello = Bytes.fromString(\"hello\");\n  int n = Bytes.len(hello);\n  Console.println(\"len={n}\");                         // len=5\n  Console.println(Bytes.toString(hello) ?? \"?\");     // hello\n\n  // A `b\"…\"` literal with \\xHH escapes — 0x48 0x69 = \"Hi\".\n  bytes raw = b\"\\x48\\x69\";\n  Console.println(Bytes.toString(raw) ?? \"?\");       // Hi\n  int rn = Bytes.len(raw);\n  Console.println(\"rawlen={rn}\");                     // rawlen=2\n\n  // Invalid UTF-8 decodes to `null` (never a fault) — composes with `??`.\n  bytes bad = b\"\\xff\\xfe\";\n  Console.println(Bytes.toString(bad) ?? \"<non-utf8>\"); // <non-utf8>\n\n  // concat + slice (half-open, bounds-clamped).\n  bytes ab = Bytes.concat(b\"foo\", b\"bar\");\n  Console.println(Bytes.toString(ab) ?? \"?\");        // foobar\n  int abn = Bytes.len(ab);\n  Console.println(\"ablen={abn}\");                     // ablen=6\n\n  bytes sl = Bytes.slice(ab, 1, 4);\n  Console.println(Bytes.toString(sl) ?? \"?\");        // oob\n\n  // start > end clamps to an empty slice (total, no fault).\n  bytes empty = Bytes.slice(ab, 5, 2);\n  int en = Bytes.len(empty);\n  Console.println(\"slempty={en}\");                    // slempty=0\n\n  // byte-vector equality.\n  bytes eq1 = b\"abc\";\n  bytes eq2 = Bytes.fromString(\"abc\");\n  if (eq1 == eq2) { Console.println(\"eq\"); } else { Console.println(\"ne\"); } // eq\n}\n",
  "cause-chain": "package Main;\n\nimport Core.Console;\n\n// M-faults Slice 2c — exception cause chains. A higher-level error can carry the lower-level error\n// that triggered it, so context is preserved instead of lost. A conventional `cause` field of type\n// `Error?` on an `Error` subtype is routed into PHP's native exception chain\n// (`parent::__construct($message, 0, $cause)`), so the transpiled PHP reports an idiomatic\n// \"caused by\" via `getPrevious()` too — while the Phorge backends read it back as a plain field.\n\nclass IoError implements Error {\n  constructor(public string message) {}\n}\n\nclass ConfigError implements Error {\n  constructor(public string message, public Error? cause) {}\n}\n\n// Simulate a low-level failure, then wrap it in a higher-level error that preserves the cause.\nfunction readConfig() -> int throws ConfigError {\n  try {\n    throw IoError(\"disk offline\");\n  } catch (IoError e) {\n    throw ConfigError(\"could not load config\", e);\n  }\n}\n\nfunction main() {\n  try {\n    var n = readConfig();\n    Console.println(\"loaded {n}\");\n  } catch (ConfigError e) {\n    Console.println(\"error: {e.message}\");\n    // `e.cause` is `Error?`; narrow it with an if-let, then `instanceof` to read the concrete cause.\n    if (var c = e.cause) {\n      if (c instanceof IoError) {\n        Console.println(\"  caused by: {c.message}\");\n      }\n    }\n  }\n}\n",
  "classes": "package Main;\nimport Core.Console;\n\nclass Engine {\n    constructor(private int power) {}\n    function powerOf() -> int { return power; }\n}\n\nclass Car {\n    // composition: a Car *has an* Engine\n    constructor(private string make, private Engine engine) {}\n\n    function makeOf() -> string { return make; }\n    // a method that calls a method on a field (the Wave-4 class-aware path)\n    function horsepower() -> int { return engine.powerOf(); }\n}\n\nfunction main() {\n    Car c = Car(\"Phorge\", Engine(250));\n    Console.println(\"{c.makeOf()} has {c.horsepower()} hp\");\n}",
  "clone-with": "package Main;\nimport Core.Console;\n\n// M-mut.4a — `obj with { field = value, … }`: a functional update that produces a FRESH instance\n// copying `obj` with the named fields replaced. The constructor is NOT re-run, and the source\n// instance is never modified — so it composes safely even before in-place mutation exists.\n\nclass Point {\n    constructor(public int x, public int y) {}\n    function dist2() -> int {\n        return this.x * this.x + this.y * this.y;\n    }\n}\n\nfunction main() {\n    Point origin = Point(0, 0);\n\n    // Override one field — `origin` is untouched.\n    Point right = origin with { x = 3 };\n    Console.println(\"origin = ({origin.x}, {origin.y})\"); // (0, 0)\n    Console.println(\"right  = ({right.x}, {right.y})\"); // (3, 0)\n\n    // Override several fields at once.\n    Point p = origin with { x = 3, y = 4 };\n    Console.println(\"p = ({p.x}, {p.y})\"); // (3, 4)\n\n    // The result is a real instance: methods work on it.\n    Console.println(\"p.dist2 = {p.dist2()}\"); // 25\n\n    // The override value can read the source's fields.\n    Point shifted = p with { x = p.x + 10 };\n    Console.println(\"shifted = ({shifted.x}, {shifted.y})\"); // (13, 4)\n}\n",
  "collections-query": "// Core.List + Core.Map query natives (M-RT S7b) — the first *generic* stdlib natives. Their\n// signatures carry type parameters (`List.reverse(List<T>) -> List<T>`, `Map.keys(Map<K,V>) ->\n// List<K>`), inferred at the call site by the same unifier as a generic free function — no\n// monomorphization, the type params never reach a backend. Byte-identical on run / runvm / real PHP.\n//\n// Map keys here are plain (non-numeric) strings: PHP arrays coerce integer-like string keys and\n// bools to int keys, so `Map.keys` over such a map would render differently under PHP (KNOWN_ISSUES);\n// plain string keys are kept verbatim. Integer arithmetic only (PHP's float `/` never enters).\npackage Main;\n\nimport Core.Console;\nimport Core.List;\nimport Core.Map;\n\nfunction main() {\n    // --- Core.List: reverse (generic) + sum (concrete List<int> -> int) ---\n    var nums = [1, 2, 3, 4, 5];\n    var rev = List.reverse(nums);\n    var head = rev[0];\n    Console.println(\"sum        = {List.sum(nums)}\");\n    Console.println(\"reversed[0] = {head}\");\n    Console.println(\"sum(rev)   = {List.sum(rev)}\");\n\n    // --- Core.Map: size / has / keys / values, insertion-ordered ---\n    var ages = [\"alice\" => 30, \"bob\" => 25, \"carol\" => 41];\n    var hasBob = Map.has(ages, \"bob\");\n    var hasDave = Map.has(ages, \"dave\");\n    Console.println(\"size       = {Map.size(ages)}\");\n    Console.println(\"has bob    = {hasBob}\");\n    Console.println(\"has dave   = {hasDave}\");\n\n    // keys() preserves insertion order; index back into the map by each key.\n    for (string name in Map.keys(ages)) {\n        var age = ages[name];\n        Console.println(\"{name} -> {age}\");\n    }\n\n    // values() feeds straight into List.sum.\n    var total = List.sum(Map.values(ages));\n    Console.println(\"total age  = {total}\");\n}\n",
  "collections": "package Main;\nimport Core.Console;\nimport Core.List;\n\nclass Point {\n    constructor(private int x, private int y) {}\n    function show() -> string { return \"({x}, {y})\"; }\n}\n\nfunction main() {\n    List<int> nums = [10, 20, 30];\n    int count = List.length(nums);  // → PHP count(); generic over the element type\n    Console.println(\"count = {count}\");\n    for (int n in nums) {\n        Console.println(\"n = {n}\");\n    }\n\n    List<List<int>> grid = [[1, 2], [3, 4]];\n    for (List<int> row in grid) {\n        for (int v in row) {\n            Console.println(\"v = {v}\");\n        }\n    }\n\n    List<Point> pts = [Point(0, 0), Point(1, 2)];\n    for (Point p in pts) {\n        Console.println(p.show());\n    }\n}",
  "compound-assign": "package Main;\nimport Core.Console;\n\n// M-mut.2 — compound assignment, increment/decrement, and null-coalesce-assign.\n// Every form below is pure SUGAR: `x op= e` lowers to `x = x op e`, `x++` to `x = x + 1`,\n// `x ??= e` to `x = x ?? e`. They reuse the M-mut.1 reassignment, so a target must be `mutable`.\n\nfunction main() {\n    // The five arithmetic compound operators.\n    mutable int x = 10;\n    x += 5; // 15\n    x -= 3; // 12\n    x *= 2; // 24\n    Console.println(\"after + - * : {x}\");\n\n    // Integer `/=` is truncating integer division (NOT float): 24 / 5 = 4.\n    x /= 5;\n    Console.println(\"after /= 5 : {x}\"); // 4\n\n    // `%=` follows the dividend's sign (like PHP): -7 % 3 = -1, 7 % -3 = 1.\n    mutable int neg = 0 - 7;\n    neg %= 3;\n    mutable int pos = 7;\n    pos %= 0 - 3;\n    Console.println(\"modulo signs : {neg} {pos}\"); // -1 1\n\n    // Statement-form increment / decrement.\n    mutable int n = 0;\n    n++;\n    n++;\n    n++;\n    n--;\n    Console.println(\"counter : {n}\"); // 2\n\n    // `??=` assigns only when the optional is currently null.\n    mutable int? a = null;\n    a ??= 7; // a was null → becomes 7\n    mutable int? b = 3;\n    b ??= 9; // b was set → unchanged\n    Console.println(\"coalesce-assign : {a ?? -1} {b ?? -1}\"); // 7 3\n\n    // Two-binding scalar observe: a compound op on `copy` must not touch `base` (value-copy).\n    int base = 5;\n    mutable int copy = base;\n    copy += 100;\n    Console.println(\"value-copy : {base} {copy}\"); // 5 105\n\n    // Compound assignment as a loop accumulator.\n    mutable int sum = 0;\n    for (int i in 1..=5) {\n        sum += i;\n    }\n    Console.println(\"sum 1..=5 : {sum}\"); // 15\n}\n",
  "control-flow": "package Main;\nimport Core.Console;\n\n// recursion\nfunction fact(int n) -> int {\n    if (n <= 1) {\n        return 1;\n    }\n    return n * fact(n - 1);\n}\n\n// mutual recursion\nfunction isEven(int n) -> bool {\n    if (n == 0) {\n        return true;\n    }\n    return isOdd(n - 1);\n}\n\nfunction isOdd(int n) -> bool {\n    if (n == 0) {\n        return false;\n    }\n    return isEven(n - 1);\n}\n\nfunction main() {\n    if (fact(5) > 100) {\n        Console.println(\"5! is big: {fact(5)}\");\n    } else {\n        Console.println(\"5! is small\");\n    }\n\n    for (int i in [0, 1, 2, 3, 4]) {\n        Console.println(\"isEven({i}) = {isEven(i)}\");\n    }\n}",
  "element-set": "package Main;\nimport Core.Console;\n\n// M-mut.5 — value-type element set: `xs[i] = e` (list) and `m[k] = e` (map). Lists and maps are\n// COPY-ON-WRITE value types: assigning one to another binding copies it, so mutating the copy\n// never affects the original — exactly like PHP arrays.\n\nfunction main() {\n    // List element set, including compound assignment (rides the M-mut.2 desugar).\n    mutable List<int> xs = [1, 2, 3];\n    xs[1] = 20;\n    xs[0] += 100;\n    xs[2] *= 5;\n    Console.println(\"xs = [{xs[0]}, {xs[1]}, {xs[2]}]\"); // [101, 20, 15]\n\n    // Copy-on-write: `ys` is an independent copy — setting an element of `ys` leaves `xs` untouched.\n    mutable List<int> ys = xs;\n    ys[0] = 999;\n    Console.println(\"xs[0] = {xs[0]}, ys[0] = {ys[0]}\"); // 101, 999\n\n    // Map element set: update an existing key, then insert a new one (insertion-ordered).\n    mutable Map<string, int> scores = [\"alice\" => 1];\n    scores[\"alice\"] = 10;\n    scores[\"bob\"] = 7;\n    Console.println(\"alice = {scores[\\\"alice\\\"]}, bob = {scores[\\\"bob\\\"]}\"); // 10, 7\n\n    // Fill a list in a loop — the natural pairing of element set with M-mut.3 loops.\n    mutable List<int> squares = [0, 0, 0, 0, 0];\n    for (mutable int i = 0; i < 5; i++) {\n        squares[i] = i * i;\n    }\n    Console.println(\"squares = [{squares[0]}, {squares[1]}, {squares[2]}, {squares[3]}, {squares[4]}]\"); // [0, 1, 4, 9, 16]\n}\n",
  "enums-match": "package Main;\nimport Core.Console;\n\n// Variant patterns (with bindings) over a payload + zero-payload enum.\n// Zero-payload variants use call form `JNull()` to construct AND to match —\n// a bare `JNull =>` arm would be a catch-all binding, not a variant pattern.\nenum Json {\n    JNull,\n    JBool(bool b),\n    JNum(int n),\n    JStr(string s),\n}\n\nfunction show(Json j) -> string {\n    return match j {\n        JNull()  => \"null\",\n        JBool(b) => \"bool {b}\",\n        JNum(n)  => \"num {n}\",\n        JStr(s)  => \"str {s}\",\n    };\n}\n\n// Literal pattern + binding pattern (catch-all) over a primitive scrutinee.\nfunction sign(int n) -> string {\n    return match n {\n        0 => \"zero\",\n        x => \"nonzero {x}\",\n    };\n}\n\nfunction main() {\n    List<Json> vals = [JNull(), JBool(true), JNum(42), JStr(\"hi\")];\n    for (Json j in vals) {\n        Console.println(show(j));\n    }\n    Console.println(sign(0));\n    Console.println(sign(7));\n}",
  "ergonomics": "package Main;\nimport Core.Console;\n\n// M3 S1 \"core ergonomics\": list indexing, integer ranges, and expression `if`.\nfunction main() {\n    // Indexing: read elements out of a list by position.\n    List<int> xs = [10, 20, 30];\n    Console.println(\"first={xs[0]} last={xs[2]}\");\n\n    // Ranges: `0..3` is exclusive (0, 1, 2). Expression `if` produces a value inline.\n    for (int i in 0..3) {\n        string kind = if (i == 1) { \"mid\" } else { \"edge\" };\n        Console.println(\"xs[{i}]={xs[i]} ({kind})\");\n    }\n\n    // `..=` is inclusive (1, 2, 3).\n    for (int n in 1..=3) {\n        Console.println(\"n={n}\");\n    }\n}",
  "errors": "package Main;\n\nimport Core.Console;\n\n// M-faults Slice 2 — checked exceptions: `throws`, `throw`, `try`/`catch`/`finally`, and `?`-throws\n// propagation. A thrown type must implement the built-in `Error` marker (transpiles to a PHP class\n// extending `\\Exception`); the compiler forces every checked exception to be caught or declared, so\n// nothing escapes silently. Faults/panics (e.g. `panic`, division by zero) are a separate, uncatchable\n// tier — see `result.phg` — and cannot appear in a runnable example (they would abort it).\n\nclass NegativeInput implements Error {\n  constructor(public string message) {}\n}\n\nclass TooLarge implements Error {\n  constructor(public string message) {}\n}\n\n// `throws A | B` declares the checked exceptions this function may raise (the union is a set).\nfunction validate(int n) -> int throws NegativeInput | TooLarge {\n  if (n < 0) {\n    throw NegativeInput(\"must not be negative\");\n  }\n  if (n > 100) {\n    throw TooLarge(\"must be at most 100\");\n  }\n  return n;\n}\n\n// `?` propagates a throwing call's exceptions to this function's own `throws` — no boilerplate.\nfunction doubled(int n) -> int throws NegativeInput | TooLarge {\n  var v = validate(n)?;\n  return v * 2;\n}\n\nfunction main() {\n  // Multiple `catch` clauses dispatch by type; `finally` runs on every path (ok, caught, or\n  // propagated). `?`-throws inside `doubled` surfaces the exception here.\n  for (int n in [50, 0 - 5, 200]) {\n    try {\n      var r = doubled(n);\n      Console.println(\"ok({n}) = {r}\");\n    } catch (NegativeInput e) {\n      Console.println(\"rejected({n}): {e.message}\");\n    } catch (TooLarge e) {\n      Console.println(\"rejected({n}): {e.message}\");\n    } finally {\n      Console.println(\"  (checked {n})\");\n    }\n  }\n\n  // A single union clause `catch (A | B e)` handles either checked error.\n  try {\n    var bad = validate(0 - 9);\n    Console.println(\"unreached\");\n  } catch (NegativeInput | TooLarge e) {\n    Console.println(\"union catch handled a checked error\");\n  }\n}\n",
  "floats": "package Main;\nimport Core.Console;\nimport Core.Math;\n\n// Float stringification is byte-identical across all three backends. The Phorge interpreter and VM\n// render a `float` with Rust's shortest-round-trip formatting (always positional, never scientific;\n// an integer-valued float drops its `.0`). The transpiler reproduces exactly that in PHP via the\n// `__phorge_float` runtime helper — so large/small magnitudes that PHP's default `echo` would print\n// in scientific notation (`1.0E+15`, `1.0E-5`) and many-digit values it would round to 14 figures\n// instead render identically to the Rust backends. (Earlier this was a transpile-only caveat; it is\n// now closed for every finite float — see KNOWN_ISSUES for the one remaining fault-domain note.)\n\nfunction main() {\n    // Irrational result — 17 significant digits. `sqrt` is IEEE-correctly-rounded, so the Rust\n    // backends and PHP compute the same double; both now render all of its digits.\n    float irrational = Math.sqrt(2.0);\n\n    // Large integer-valued float (16 digits) — PHP's default `echo` would show `1.2345...E+15`.\n    float big = 1234567890123456.0;\n\n    // Small magnitudes — PHP's default `echo` would show `1.23E-5` / `1.0E-5`.\n    float small = 0.0000123;\n    float tiny = 0.00001;\n\n    // A high-precision terminating literal, and the integer-valued / short cases for good measure.\n    float pi = 3.141592653589793;\n    float whole = 42.0;\n    float half = 12.5;\n\n    Console.println(\"sqrt(2) = {irrational}\");\n    Console.println(\"big = {big}\");\n    Console.println(\"small = {small}, tiny = {tiny}\");\n    Console.println(\"pi = {pi}, whole = {whole}, half = {half}\");\n}\n",
  "functions": "package Main;\nimport Core.Console;\n\n// Functions in Phorge: typed parameters and a return type.\n// A function with no `-> T` (like `main`) returns nothing.\n\n// Two typed parameters, returns int.\nfunction add(int a, int b) -> int {\n    return a + b;\n}\n\n// A string in, a string out — interpolation builds the result.\nfunction greet(string name) -> string {\n    return \"hello, {name}\";\n}\n\n// Functions compose: `shout` calls `greet`.\nfunction shout(string name) -> string {\n    return \"{greet(name)}!\";\n}\n\n// A function may return a List<int>; a range materializes into one.\nfunction upTo(int n) -> List<int> {\n    return 0..n;\n}\n\n// No return type: this function just prints.\nfunction banner(string title) {\n    Console.println(\"== {title} ==\");\n}\n\nfunction main() {\n    banner(\"functions\");\n    Console.println(\"add(2, 3) = {add(2, 3)}\");\n    Console.println(greet(\"phorge\"));\n    Console.println(shout(\"phorge\"));\n\n    // Call results feed directly into other expressions.\n    int total = add(add(1, 2), add(3, 4));\n    Console.println(\"nested add = {total}\");\n\n    for (int i in upTo(4)) {\n        Console.println(\"i = {i}\");\n    }\n}",
  "generic-enums": "// Generic enums (M-RT) — TypeScript-style `<T>` on an *enum*, the sum-type companion to generic\n// classes (`Box<T>`). The two canonical cases ship in the language's own idiom: `Option<T>` (a value\n// that may be absent) and `Result<T, E>` (a success `T` or an error `E`).\n//\n// A type parameter is in scope across every variant's payload. It is **inferred at the variant\n// constructor** (`Some(7)` ⇒ `Option<int>`, `Ok(1)` ⇒ `Result<int, …>`) and recovered at every\n// `match`: matching an `Option<int>` binds `Some(n)` with `n: int`, so the payload is usable at its\n// concrete type. A variant that does not mention a parameter (`None`, or `Ok` w.r.t. `E`) can't infer\n// it — annotate the binding to fix it (`Option<int> n = None();`). As with generic classes/functions\n// there is **no monomorphization**: after checking, the parameters are *erased* (a `T` payload becomes\n// PHP `mixed`), so the interpreter, the bytecode VM, and the transpiled PHP run identical,\n// type-variable-free code — byte-for-byte identical output.\n\npackage Main;\n\nimport Core.Console;\n\n// Absent-or-present. `Some` carries a `T`; `None` carries nothing.\nenum Option<T> {\n    None,\n    Some(T value),\n}\n\n// Success-or-failure. `Ok` carries the success `T`; `Err` carries the error `E`.\nenum Result<T, E> {\n    Ok(T value),\n    Err(E error),\n}\n\n// Takes a concrete `Option<int>`; the `Some` payload binds at `int`, so `n` is a real integer.\nfunction describe(Option<int> o) -> string {\n    return match o {\n        Some(n) => \"some {n}\",\n        None()  => \"none\",\n    };\n}\n\n// Returns a generic enum: divide, or report the reason as a string error.\nfunction safeDiv(int a, int b) -> Result<int, string> {\n    return match b {\n        0 => Err(\"divide by zero\"),\n        _ => Ok(a / b),\n    };\n}\n\nfunction report(Result<int, string> r) -> string {\n    return match r {\n        Ok(v)  => \"ok {v}\",\n        Err(e) => \"err {e}\",\n    };\n}\n\nfunction main() {\n    var some = Some(7); // Option<int> — T inferred from `7`\n    Option<int> none = None(); // None mentions no T — annotate to fix Option<int>\n\n    Console.println(describe(some)); // some 7\n    Console.println(describe(none)); // none\n\n    // A bound payload is *type-checked* at its concrete type (here `n: int`), so the front end accepts\n    // it anywhere an int is expected. It does carry the erased-generics limitation: a generic payload\n    // is `mixed` to the backend, so it is not a *specialized* arithmetic operand on the VM — to do math\n    // on it, return it into a typed local first (`int got = …; got + got`), exactly as with a generic\n    // class method result. String interpolation of the payload needs no such hint and works directly.\n    var os = Some(\"phorge\"); // Option<string>\n    string label = match os {\n        Some(s) => \"label {s}\",\n        None()  => \"label none\",\n    };\n    Console.println(label); // label phorge\n\n    Console.println(report(safeDiv(10, 2))); // ok 5\n    Console.println(report(safeDiv(1, 0))); // err divide by zero\n}\n",
  "generic-methods": "// Generic methods (M-RT generics-all) — TypeScript-style `<T>` type parameters on *methods*.\n//\n// A method can be generic just like a free function: the type parameter is declared after the\n// method name (`identity<T>`) and inferred at each call site from the argument types. The class\n// itself is NOT generic here — only the method introduces `T`. As with generic free functions\n// there is NO monomorphization: after type-checking every `T` is erased to a plain runtime value\n// (PHP `mixed`), so the interpreter, the bytecode VM, and the transpiled PHP run identical code —\n// byte-for-byte identical output.\n\npackage Main;\n\nimport Core.Console;\n\n// A stateless utility — no fields, no constructor (instantiated as `Util()`).\nclass Util {\n  // The classic: returns its argument unchanged, at whatever type it was called with.\n  function identity<T>(T x) -> T {\n    return x;\n  }\n\n  // `T` is inferred from the list's element type; the fallback shares it, so the whole call is\n  // checked against one consistent `T`.\n  function firstOr<T>(List<T> xs, T fallback) -> T {\n    for (T x in xs) {\n      return x;\n    }\n    return fallback;\n  }\n\n  // A type parameter can appear inside a *function-typed* parameter too: `f` maps a `T` to a `T`.\n  // Unification descends into the `(T) -> T` shape to bind `T`, and the closure is invoked inside\n  // the method body.\n  function applyTwice<T>(T x, (T) -> T f) -> T {\n    return f(f(x));\n  }\n}\n\nfunction main() {\n  var u = Util();\n\n  // `identity` reused at three different concrete types — one method definition, no duplication.\n  int n = u.identity(7);\n  string s = u.identity(\"phorge\");\n  bool flag = u.identity(true);\n\n  // `firstOr` over a non-empty `List<int>` → `T = int`, returns the first element.\n  List<int> xs = [10, 20, 30];\n  int head = u.firstOr(xs, -1);\n\n  // A generic method taking an inline lambda: increments 5 twice → 7.\n  int bumped = u.applyTwice(5, fn(int v) => v + 1);\n\n  Console.println(\"identity: {n} {s} {flag}\");\n  Console.println(\"firstOr head: {head}\");\n  Console.println(\"applyTwice: {bumped}\");\n}\n",
  "generic-types": "// Generic types / classes (M-RT generics-all) — TypeScript-style `<T>` on a *class*.\n//\n// A class can declare type parameters after its name: `class Box<T>`, `class Pair<A, B>`. The\n// parameter is in scope across the whole class — the field, the constructor, and every method. It is\n// **inferred at construction** from the constructor arguments (`Box(7)` ⇒ `Box<int>`) and recovered\n// at each use site (`Box(7).get()` is `int`; assigning it to a `string` would be a type error). As\n// with generic functions and methods there is **no monomorphization**: after type-checking every\n// type parameter is *erased* (a `T` field becomes a plain runtime value / PHP `mixed`), so the\n// interpreter, the bytecode VM, and the transpiled PHP all run identical, type-variable-free code —\n// byte-for-byte identical output. An instance carries no type argument at runtime: `instanceof\n// Box<int>` is just `instanceof Box`.\n\npackage Main;\n\nimport Core.Console;\n\n// A one-field generic container. `T` flows through the promoted constructor field and the methods.\nclass Box<T> {\n  constructor(private T value) {}\n\n  // Returns the stored value at whatever concrete type the box was constructed with.\n  function get() -> T {\n    return this.value;\n  }\n\n  // A method *taking* a `T`: the parameter is checked at the instance's concrete type, so\n  // `Box(7).orElse(0)` type-checks but `Box(7).orElse(\"x\")` would not.\n  function orElse(T fallback) -> T {\n    return this.value;\n  }\n}\n\n// Two type parameters, inferred independently from the two constructor arguments.\nclass Pair<A, B> {\n  constructor(private A first, private B second) {}\n  function left() -> A {\n    return this.first;\n  }\n  function right() -> B {\n    return this.second;\n  }\n}\n\nfunction main() {\n  var bi = Box(7); // Box<int>  — T inferred from `7`\n  int x = bi.get(); // int\n  int y = bi.orElse(0); // int — the T-typed parameter accepts an int\n\n  var bs = Box(\"phorge\"); // Box<string>\n  string s = bs.get(); // string\n\n  var p = Pair(1, \"one\"); // Pair<int, string> — A=int, B=string\n  int a = p.left();\n  string b = p.right();\n\n  Console.println(\"box int: {x} {y}\");\n  Console.println(\"box str: {s}\");\n  Console.println(\"pair: {a} {b}\");\n}\n",
  "generics": "// Erased generics (M-RT S7) — TypeScript-style `<T>` type parameters on free functions.\n//\n// A generic function is written once and used at many concrete types; the type parameter is\n// inferred at each call site from the argument types. There is NO monomorphization: after\n// type-checking, the type parameters are *erased* (every `T` becomes PHP `mixed` / a plain runtime\n// value), so the interpreter, the bytecode VM, and the transpiled PHP all run the exact same\n// type-variable-free code — byte-for-byte identical output.\n\npackage Main;\n\nimport Core.Console;\n\n// The classic: returns its argument unchanged, at whatever type it was called with.\nfunction identity<T>(T x) -> T {\n  return x;\n}\n\n// `T` is inferred from the list's element type; the fallback shares it, so the whole call is\n// checked against one consistent `T`.\nfunction firstOr<T>(List<T> xs, T fallback) -> T {\n  for (T x in xs) {\n    return x;\n  }\n  return fallback;\n}\n\n// A type parameter can appear inside a *function-typed* parameter too: `f` maps a `T` to a `T`.\n// Unification descends into the `(T) -> T` shape to bind `T` from the function value passed in.\nfunction applyTwice<T>(T x, (T) -> T f) -> T {\n  return f(f(x));\n}\n\n// Two occurrences of the same parameter must agree: both `a` and `b` are the inferred `T`.\nfunction lastOfTwo<T>(T a, T b) -> T {\n  return b;\n}\n\nfunction main() {\n  // `identity` reused at three different concrete types — one definition, no duplication.\n  int n = identity(7);\n  string s = identity(\"phorge\");\n  bool flag = identity(true);\n\n  // `firstOr` over a non-empty `List<int>` → `T = int`, returns the first element.\n  List<int> xs = [10, 20, 30];\n  int head = firstOr(xs, -1);\n\n  // `applyTwice` with an inline lambda: increments 5 twice → 7.\n  int bumped = applyTwice(5, fn(int v) => v + 1);\n\n  // `lastOfTwo` over strings.\n  string last = lastOfTwo(\"alpha\", \"omega\");\n\n  Console.println(\"identity: {n} {s} {flag}\");\n  Console.println(\"firstOr head: {head}\");\n  Console.println(\"applyTwice: {bumped}\");\n  Console.println(\"lastOfTwo: {last}\");\n}\n",
  "higher-order": "// Core.List higher-order natives (M-RT S7b-3): map / filter / reduce. These are the first natives\n// that take a *closure* argument — the runtime calls the closure once per element, on whichever\n// backend is running, via one shared native body (the interpreter wraps `call_closure`; the VM wraps\n// a re-entrant `call_closure_value`). They are generic (the element type `T`, and map/reduce's result\n// type `U`, are inferred at the call site like any generic free function) and erase to PHP's\n// `array_map` / `array_filter` / `array_reduce`. Byte-identical on run / runvm / real PHP.\n//\n// Results are shown via `List.sum` and indexing — PHP cannot `echo` an array directly, so no example\n// prints a whole list. Integer arithmetic only (PHP's float `/` never enters).\npackage Main;\n\nimport Core.Console;\nimport Core.List;\n\nfunction main() {\n    var nums = [1, 2, 3, 4, 5];\n\n    // map: double each element.\n    var doubled = List.map(nums, fn(int x) => x * 2);\n    Console.println(\"map sum     = {List.sum(doubled)}\");\n    Console.println(\"map[0]      = {doubled[0]}\");\n\n    // filter: keep the even elements (the predicate returns bool).\n    var evens = List.filter(nums, fn(int x) => x % 2 == 0);\n    Console.println(\"filter sum  = {List.sum(evens)}\");\n    Console.println(\"filter[0]   = {evens[0]}\");\n\n    // reduce: product over the list, seeded with 1.\n    var product = List.reduce(nums, 1, fn(int acc, int x) => acc * x);\n    Console.println(\"reduce prod = {product}\");\n\n    // closures capture enclosing locals by value — `factor` is captured into the lambda.\n    var factor = 10;\n    var scaled = List.map(nums, fn(int x) => x * factor);\n    Console.println(\"scaled sum  = {List.sum(scaled)}\");\n\n    // composition: filter, then map, then reduce — higher-order natives chain like any call.\n    var kept = List.filter(nums, fn(int x) => x > 2);\n    var squared = List.map(kept, fn(int x) => x * x);\n    Console.println(\"compose sum = {List.sum(squared)}\");\n}\n",
  "html": "package Main;\n\n// Core.Html — typed, auto-escaping HTML.\n// `Html` and `Attr` are DISTINCT types from `string`: untrusted text only reaches\n// rendered HTML through `Html.text` (auto-escape) or the audited `Html.raw`. That\n// non-interchangeability is the XSS-safety wall — enforced by the type checker.\n//\n//   Wave 1  the escape KERNEL    text / raw / render\n//   Wave 2  the element BUILDERS  attr / boolAttr / el / voidEl / concat\n//   Wave 3  the `html\"…\"` literal sugar  html\"<h1>{name}</h1>\"\nimport Core.Console;\nimport Core.Html;\n\n// Wave-1 style: hand-written markup wrapped with Html.raw; the dynamic value escaped.\nfunction field(string label, string value) -> Html {\n  return Html.raw(\"<li>{label}: {Html.render(Html.text(value))}</li>\");\n}\n\n// Wave-2 style: the same row built from typed fragments — no hand-written markup.\nfunction row(string label, string value) -> Html {\n  return Html.el(\"li\", [Html.attr(\"data-label\", label)],\n                 [Html.text(\"{label}: \"), Html.text(value)]);\n}\n\n// Wave-3 style: write the markup directly and interpolate by type. Each {hole} escapes\n// unless it is already an Html value — so `{label}`/`{value}` (strings) are escaped, while\n// nesting another html\"…\" or a builder embeds verbatim. A multi-line literal works too.\nfunction card(string title, Html bodyHtml) -> Html {\n  return html\"<section>\n    <h2>{title}</h2>\n    {bodyHtml}\n  </section>\";\n}\n\nfunction main() {\n  string name = \"Tom & \\\"Jerry\\\"\";\n  string bio = \"<script>alert(1)</script>\";\n\n  // --- Wave 1: the escape kernel ---\n  Html safe = Html.text(name);\n  Console.println(Html.render(safe));                // Tom &amp; &quot;Jerry&quot;\n  Html hr = Html.raw(\"<hr/>\");\n  Console.println(Html.render(hr));                   // <hr/>\n  Console.println(Html.render(field(\"name\", name)));  // <li>name: Tom &amp; &quot;Jerry&quot;</li>\n  Console.println(Html.render(field(\"bio\", bio)));    // <li>bio: &lt;script&gt;alert(1)&lt;/script&gt;</li>\n\n  // --- Wave 2: typed element builders ---\n  // An element with an attribute (value escaped) and escaped text children.\n  Html link = Html.el(\"a\", [Html.attr(\"href\", \"/p?x=1&y=2\")], [Html.text(\"Tom & Jerry\")]);\n  Console.println(Html.render(link));   // <a href=\"/p?x=1&amp;y=2\">Tom &amp; Jerry</a>\n\n  // A no-attribute element — empty [] is accepted in call-argument position.\n  Html para = Html.el(\"p\", [], [Html.text(bio)]);\n  Console.println(Html.render(para));   // <p>&lt;script&gt;alert(1)&lt;/script&gt;</p>\n\n  // A self-closing void element with an attribute.\n  Html img = Html.voidEl(\"img\", [Html.attr(\"src\", \"a&b.png\")]);\n  Console.println(Html.render(img));    // <img src=\"a&amp;b.png\"/>\n\n  // A boolean (valueless) attribute.\n  Html btn = Html.el(\"button\", [Html.boolAttr(\"disabled\")], [Html.text(\"Go\")]);\n  Console.println(Html.render(btn));    // <button disabled>Go</button>\n\n  // concat joins sibling fragments into one Html.\n  Html doc = Html.concat([Html.raw(\"<hr/>\"), row(\"name\", name)]);\n  Console.println(Html.render(doc));    // <hr/><li data-label=\"name\">name: Tom &amp; &quot;Jerry&quot;</li>\n\n  // --- Wave 3: the html\"…\" literal sugar ---\n  // String holes auto-escape; a primitive hole stringifies then escapes.\n  int year = 2026;\n  Html h = html\"<h1>{name}</h1><p>since {year}</p>\";\n  Console.println(Html.render(h));      // <h1>Tom &amp; &quot;Jerry&quot;</h1><p>since 2026</p>\n\n  // An Html hole embeds verbatim — no double-escape (the value is already safe).\n  Html badge = Html.el(\"span\", [Html.boolAttr(\"hidden\")], [Html.text(bio)]);\n  Html line = html\"<div>{badge}</div>\";\n  Console.println(Html.render(line));   // <div><span hidden>&lt;script&gt;alert(1)&lt;/script&gt;</span></div>\n\n  // Compose: pass an html\"…\" fragment into a helper that wraps it in more (multi-line) markup.\n  Html inner = html\"<p>{name}</p>\";\n  Console.println(Html.render(card(\"Profile\", inner)));\n\n  // --- Option 1: named per-tag helpers ---\n  // Each tag is sugar over el/voidEl with the tag baked in: Html.div(attrs, children),\n  // Html.hr(attrs). Same auto-escaping (attribute values + text), same byte output.\n  Html bar = Html.nav([Html.attr(\"class\", \"top\")],\n                      [Html.a([Html.attr(\"href\", \"/?a=1&b=2\")], [Html.text(\"Home & Away\")])]);\n  Console.println(Html.render(bar));   // <nav class=\"top\"><a href=\"/?a=1&amp;b=2\">Home &amp; Away</a></nav>\n\n  Html items = Html.ul([], [Html.li([], [Html.text(name)]), Html.li([], [Html.text(bio)])]);\n  // <ul><li>Tom &amp; &quot;Jerry&quot;</li><li>&lt;script&gt;alert(1)&lt;/script&gt;</li></ul>\n  Console.println(Html.render(items));\n\n  Html rule = Html.hr([]);              // a void element: <hr/>\n  Console.println(Html.render(rule));\n}\n",
  "inference": "package Main;\nimport Core.Console;\n\n// `type` alias: a domain-specific name for a primitive. It is compile-time only — the checker\n// resolves `Celsius` to `int`, and it is fully erased from the transpiled PHP.\ntype Celsius = int;\n\nfunction freezing() -> Celsius {\n    return 0;\n}\n\nfunction boiling() -> Celsius {\n    return 100;\n}\n\nfunction main() {\n    // `var`: the binding's type is inferred from its initializer, yet stays fully static —\n    // `label` is a string, `lo`/`hi`/`range` are ints, checked like any explicit annotation.\n    var label = \"water\";\n    var lo = freezing();\n    var hi = boiling();\n    var range = hi - lo;\n    Console.println(\"{label}: {lo} to {hi} ({range} degrees)\");\n}",
  "inheritance-lattice": "// Subtyping and `instanceof` across the full inheritance lattice (M-RT S6c.3).\n//\n// A subclass is a subtype of *every* ancestor — its parent classes (single and multiple) and their\n// interfaces. That subtyping is observable three ways, all shown below:\n//   1. `instanceof` against any ancestor class is true (not just against interfaces).\n//   2. a value flows into an ancestor-typed binding (a parent-typed local / parameter).\n//   3. a `match` type-pattern narrows on an ancestor class.\n//\n// Under the hood a multi-parent class lowers to PHP `implements I<Parent>` (interface + trait), so the\n// transpiler tests the *interface* form (`instanceof ISwimmer`) — a Duck implements ISwimmer but does\n// not `extends Swimmer`. The interpreter and VM share one subtype oracle (parent classes AND\n// interfaces), so all three backends agree byte-for-byte.\npackage Main;\n\nimport Core.Console;\n\nopen class Animal {\n    open function name() -> string {\n        return \"animal\";\n    }\n}\n\n// Single inheritance: Fish IS-A Animal.\nopen class Fish extends Animal {\n    open function move() -> string {\n        return \"swims\";\n    }\n}\n\nopen class Bird extends Animal {\n    open function move() -> string {\n        return \"flies\";\n    }\n}\n\n// Multiple inheritance: a Duck is a Fish AND a Bird (and, through both, an Animal — the diamond).\nclass Duck extends Fish, Bird {\n    use Fish.move\n}\n\n// A parameter typed as an ancestor accepts any subtype (subtyping at a call boundary).\nfunction describe(Animal a) -> string {\n    return a.name();\n}\n\nfunction main() {\n    Duck d = Duck();\n\n    // (1) `instanceof` against every ancestor in the lattice — all true.\n    Console.println(\"{d instanceof Duck} {d instanceof Fish} {d instanceof Bird} {d instanceof Animal}\");\n\n    // (2) the Duck flows into ancestor-typed bindings; dispatch stays dynamic.\n    Fish f = d;\n    Animal a = d;\n    Console.println(\"{f.move()} {a.name()}\");\n    Console.println(describe(d)); // a Duck passed where an Animal is expected\n\n    // (3) a non-subtype test is false — Bird is an ancestor of Duck, but a fresh Animal is not a Bird.\n    Animal plain = Animal();\n    Console.println(\"{plain instanceof Bird}\");\n}\n",
  "inheritance-multi": "// Multiple inheritance with explicit resolution (M-RT S6b).\n//\n// Phorge supports real multiple inheritance: a class may `extend` several parents at once. PHP has no\n// multiple inheritance, so the transpiler lowers each parent to an interface + trait and the subclass\n// `implements` the interfaces and `use`s the traits — the model the field (Haxe, Hack) uses.\n//\n// When two parents supply a method of the same name, Phorge will NOT silently pick one: the collision\n// must be resolved explicitly with `use P.m` (pick a parent), `rename P.m as n` (keep both), or\n// `exclude P.m` (drop one) — else `E-MI-CONFLICT`. A *diamond* shared base (a method reached through\n// two arms that both resolve to the SAME declaring method) auto-merges and is never a conflict.\n//\n// (Inherited fields and constructors across multiple parents land in a later slice; this guide stays\n// field-free, like the single-inheritance guide.)\npackage Main;\n\nimport Core.Console;\n\nopen class Animal {\n    // Reached by Duck through BOTH Swimmer and Flyer — but it is the same `Animal.name`, so it\n    // auto-merges (the diamond): no conflict, no resolution clause needed.\n    function name() -> string {\n        return \"animal\";\n    }\n}\n\nopen class Swimmer extends Animal {\n    open function move() -> string {\n        return \"swims\";\n    }\n}\n\nopen class Flyer extends Animal {\n    open function move() -> string {\n        return \"flies\";\n    }\n}\n\n// Duck inherits from two parents. `move()` collides (Swimmer vs Flyer) and is resolved explicitly;\n// `name()` is the shared `Animal.name` reached through both arms (auto-merged).\nclass Duck extends Swimmer, Flyer {\n    use Swimmer.move\n}\n\nfunction main() {\n    Duck d = Duck();\n    Console.println(d.move()); // \"swims\" — resolved by `use Swimmer.move`\n    Console.println(d.name()); // \"animal\" — diamond shared base, auto-merged\n}\n",
  "inheritance-state": "// Multiple inheritance with state: composed constructors + fields + `instanceof` (M-RT S6c).\n//\n// Phorge composes a multi-parent class's *state*, not just its methods. A class with several parents\n// and NO constructor of its own gets a synthesized orchestrating constructor: its parameters are the\n// parents' constructor parameters concatenated in `extends` order, and constructing it runs each\n// parent's constructor (with its slice of the arguments) on the one new instance — so every inherited\n// field is initialized. A parent constructor may carry a body, not just promoted parameters.\n//\n// PHP has no multiple inheritance, so each parent lowers to an interface + a trait; the trait holds the\n// fields as plain properties (two trait constructors would collide), and the subclass gets a single\n// `__construct` that assigns them. The interpreter and VM run the same composed plan. All three\n// backends agree byte-for-byte.\npackage Main;\n\nimport Core.Console;\n\n// A parent whose constructor is pure promotion (declares + stores `name`).\nopen class Named {\n    constructor(public string name) {}\n\n    function label() -> string {\n        return this.name;\n    }\n}\n\n// A parent whose constructor has a *body* — it derives a stored field from its argument.\nopen class Paid {\n    mutable int annual;\n    constructor(int monthly) {\n        this.annual = monthly * 12;\n    }\n}\n\n// Two orthogonal parents, no own constructor → a synthesized ctor(string name, int monthly).\nclass Employee extends Named, Paid {\n    function summary() -> string {\n        return \"{this.name}: {this.annual}/yr\";\n    }\n}\n\nfunction main() {\n    Employee e = Employee(\"Ada\", 1000);\n\n    // Inherited state from BOTH parents is initialized: Named's promoted `name`, Paid's derived `annual`.\n    Console.println(e.summary());   // Ada: 12000/yr\n    Console.println(e.label());     // inherited method reads the inherited field\n\n    // An Employee is a subtype of every ancestor (S6c.3): it flows into a parent-typed binding and\n    // answers `instanceof` for each parent.\n    Named n = e;\n    Console.println(n.label());\n    Console.println(\"{e instanceof Named} {e instanceof Paid} {e instanceof Employee}\");\n}\n",
  "inheritance": "// Single inheritance with `open`/`final` and method override (M-RT S6a).\n//\n// Phorge is *final-by-default* — the inheritance sibling of immutable-by-default. A class must be\n// declared `open` to be extended, and a method must be declared `open` to be overridden. A subclass\n// inherits its parent's methods, may override the `open` ones, and is a subtype of its parent (so it\n// flows into a parent-typed binding). Dispatch is dynamic: an inherited method that calls another\n// method runs the *subclass's* override.\n//\n// (Constructors and inherited fields land in a later slice; this guide stays field-free.)\npackage Main;\n\nimport Core.Console;\n\nopen class Greeter {\n    // Not `open`: subclasses inherit it unchanged and cannot replace it. It calls `kind()`, which a\n    // subclass *can* override — so the inherited `greet()` adapts to the actual class.\n    function greet() -> string {\n        var k = this.kind();\n        return \"Hello from a {k}\";\n    }\n\n    // `open`: a subclass may override this method.\n    open function kind() -> string {\n        return \"greeter\";\n    }\n}\n\nclass LoudGreeter extends Greeter {\n    // Overrides the `open` `kind()`. `greet()` is inherited unchanged.\n    function kind() -> string {\n        return \"loud greeter\";\n    }\n}\n\nfunction main() {\n    LoudGreeter g = LoudGreeter();\n    Console.println(g.greet()); // inherited greet() dispatches to the overridden kind()\n    Console.println(g.kind());\n\n    // A LoudGreeter flows into a Greeter-typed binding (subtyping); dispatch stays dynamic.\n    Greeter base = g;\n    Console.println(base.greet());\n}\n",
  "instanceof": "// `instanceof` — the runtime type-test operator (M-RT S1).\n//\n// `value instanceof ClassName` evaluates to a `bool`: true exactly when `value` is an instance of\n// that class, false otherwise (never a fault — even for a value of an unrelated type). It replaces\n// the old value-equality `is` alias. Inside an `if (x instanceof C) { … }`, the checker smart-casts\n// `x` to `C` in the then-block, so member access through it type-checks.\npackage Main;\nimport Core.Console;\n\nclass Circle {\n    constructor(public int radius) {}\n}\n\nclass Square {\n    constructor(public int side) {}\n}\n\n// `c` is already a `Circle`, so the test is true and the smart-cast lets us read `c.radius`.\nfunction describe(Circle c) -> string {\n    if (c instanceof Circle) {\n        return \"circle r={c.radius}\";\n    }\n    return \"not a circle\";\n}\n\nfunction main() {\n    Circle c = Circle(2);\n    Square s = Square(3);\n\n    Console.println(\"{c instanceof Circle}\"); // true  — c is a Circle\n    Console.println(\"{c instanceof Square}\");  // false — a Circle is not a Square\n    Console.println(\"{s instanceof Square}\");  // true  — s is a Square\n    Console.println(describe(c));              // circle r=2\n}\n",
  "interfaces": "// Interfaces + `implements` + `instanceof` against an interface (Rich Types — M-RT S2).\n//\n// An interface is a named contract of method signatures. A class `implements` one (or several),\n// and is then a *subtype* of it: a concrete instance flows into an interface-typed slot, and code\n// written against the interface works for every implementer. `instanceof` tests against a class\n// AND an interface; inside `if (x instanceof T)` the operand is smart-cast to `T`.\npackage Main;\n\nimport Core.Console;\n\n// A contract: anything that can speak.\ninterface Speaker {\n    function speak() -> string;\n}\n\n// Interfaces compose by `extends`: a Pet is a Speaker that also has a name.\ninterface Pet extends Speaker {\n    function petName() -> string;\n}\n\nclass Dog implements Pet {\n    constructor(public string dogName) {}\n    function speak() -> string { return \"Woof\"; }\n    function petName() -> string { return this.dogName; }\n}\n\nclass Robot implements Speaker {\n    function speak() -> string { return \"Beep\"; }\n}\n\n// Polymorphism through an interface-typed parameter: `announce` knows only the contract.\nfunction announce(Speaker s) -> string {\n    return s.speak();\n}\n\nfunction main() {\n    var d = Dog(\"Rex\");\n    var r = Robot();\n\n    // Called polymorphically — both a Dog and a Robot are Speakers.\n    Console.println(announce(d)); // Woof\n    Console.println(announce(r)); // Beep\n\n    // `instanceof` against a class and against (extended) interfaces.\n    Console.println(\"{d instanceof Dog}\");     // true\n    Console.println(\"{d instanceof Speaker}\"); // true  (Dog implements Pet, Pet extends Speaker)\n    Console.println(\"{d instanceof Pet}\");     // true\n    Console.println(\"{r instanceof Speaker}\"); // true\n    Console.println(\"{r instanceof Pet}\");     // false (Robot is only a Speaker)\n\n    // A class instance flows into an interface-typed binding (nominal subtyping).\n    Speaker sp = d;\n    // Smart-cast: a Speaker known to be a Dog reads the Dog's own field.\n    if (sp instanceof Dog) {\n        Console.println(sp.dogName); // Rex\n    }\n}\n",
  "intersections": "// Intersection types `A & B` (Rich Types — M-RT S5).\n//\n// An intersection `A & B` is the narrowing dual of a union: a value that satisfies *both* members at\n// once. A parameter typed `Drawable & Named` accepts only a value whose class implements BOTH\n// interfaces — and inside, BOTH interfaces' methods are in scope on it. Members are interfaces (plus\n// at most one concrete class — a value has exactly one class). Transpiles 1:1 to PHP 8.1 `A&B`.\npackage Main;\n\nimport Core.Console;\n\n// Two independent contracts.\ninterface Drawable {\n    function draw() -> string;\n}\n\ninterface Named {\n    function name() -> string;\n}\n\n// A class can implement several interfaces, making it a subtype of each.\nclass Badge implements Drawable, Named {\n    constructor(public string label) {}\n    function draw() -> string { return \"[{this.label}]\"; }\n    function name() -> string { return this.label; }\n}\n\nclass Sticker implements Drawable, Named {\n    constructor(public string text) {}\n    function draw() -> string { return \"<{this.text}>\"; }\n    function name() -> string { return this.text; }\n}\n\n// The intersection in action: `x` is known to be BOTH Drawable and Named, so a method from EACH\n// interface is callable on it — no narrowing needed (that is the whole point of an intersection).\nfunction describe(Drawable & Named x) -> string {\n    return \"{x.name()} => {x.draw()}\";\n}\n\n// some-member-out: an `A & B` value flows into a slot typed as just one of its members.\nfunction justDraw(Drawable d) -> string {\n    return d.draw();\n}\n\nfunction main() {\n    var badge = Badge(\"ok\");\n    var sticker = Sticker(\"hi\");\n\n    // Both implement Drawable AND Named, so both flow into `Drawable & Named`.\n    Console.println(describe(badge));   // ok => [ok]\n    Console.println(describe(sticker)); // hi => <hi>\n\n    // A & B narrows out to a single member without a cast.\n    Console.println(justDraw(badge));   // [ok]\n    Console.println(justDraw(sticker)); // <hi>\n}\n",
  "lambdas-pipe": "package Main;\nimport Core.Console;\n\nfunction dbl(int x) -> int { return x * 2; }\nfunction inc(int x) -> int { return x + 1; }\n\n// higher-order: a lambda passed to a user function\nfunction twice(int x, (int) -> int f) -> int { return f(f(x)); }\n\nfunction main() {\n    var add10 = fn(int x) => x + 10;          // expression-body lambda\n    var scaled = fn(int x) -> int {           // statement-body lambda (captures none)\n        var t = x * x;\n        return t + 1;\n    };\n    Console.println(\"{add10(5)}\");            // 15\n    Console.println(\"{scaled(4)}\");           // 17\n    Console.println(\"{twice(3, add10)}\");     // 23\n    Console.println(\"{5 |> dbl |> inc}\");     // inc(dbl(5)) = 11\n    Console.println(\"{3 |> fn(int v) => v + 100}\"); // 103\n    Console.println(\"{twice(2, dbl)}\");       // dbl(dbl(2)) = 8  (named-fn ref)\n}\n",
  "loops": "package Main;\nimport Core.Console;\n\n// M-mut.3 — condition loops, made useful by mutation: `while`, `do-while`, C-style `for`,\n// while-let, plus `break` and `continue`. Every loop lowers to plain jumps (no new opcode).\n\nfunction main() {\n    // `while`: test before each iteration.\n    mutable int i = 0;\n    mutable int sum = 0;\n    while (i < 5) {\n        sum += i;\n        i += 1;\n    }\n    Console.println(\"while sum 0..4 = {sum}\"); // 10\n\n    // `do-while`: the body runs once before the first test.\n    mutable int tries = 0;\n    do {\n        tries += 1;\n    } while (tries < 3);\n    Console.println(\"do-while tries = {tries}\"); // 3\n\n    // C-style `for (init; cond; step)` — the counter must be `mutable` (the step reassigns it).\n    mutable int product = 1;\n    for (mutable int k = 1; k <= 4; k++) {\n        product *= k;\n    }\n    Console.println(\"for 4! = {product}\"); // 24\n\n    // `continue` skips the rest of an iteration; `break` exits the loop.\n    mutable int evens = 0;\n    for (mutable int n = 0; n < 100; n++) {\n        if (n == 10) {\n            break;\n        }\n        if (n % 2 == 1) {\n            continue;\n        }\n        evens += 1;\n    }\n    Console.println(\"evens below 10 = {evens}\"); // 0,2,4,6,8 → 5\n\n    // Nested loops: an inner `break` exits only the inner loop.\n    mutable int cells = 0;\n    for (mutable int r = 0; r < 3; r += 1) {\n        for (mutable int c = 0; c < 9; c += 1) {\n            if (c == 4) {\n                break;\n            }\n            cells += 1;\n        }\n    }\n    Console.println(\"grid cells = {cells}\"); // 3 rows * 4 cols = 12\n\n    // while-let: loop while an optional is non-null, binding its inner value.\n    mutable int? next = 3;\n    mutable int drained = 0;\n    while (var v = next) {\n        drained += v;\n        next = null; // a real queue would hand back the next element\n    }\n    Console.println(\"while-let drained = {drained}\"); // 3\n}\n",
  "maps": "package Main;\nimport Core.Console;\n\n// M-RT S3 \"Map foundation\": `Map<K, V>` literals `[k => v]` and indexing `m[k]`.\n// Keys are the hashable subset (int / bool / string); a missing key faults cleanly.\nfunction main() {\n    // A string-keyed lookup table (Map<string, int>).\n    Map<string, int> ages = [\"alice\" => 30, \"bob\" => 25, \"carol\" => 41];\n    // A string-literal index inside \"{…}\" would nest quotes (the shared interpolation rule),\n    // so bind the lookup to a local first, then interpolate the local.\n    var alice = ages[\"alice\"];\n    var carol = ages[\"carol\"];\n    Console.println(\"alice={alice} carol={carol}\");\n\n    // A map-index result is a first-class arithmetic operand — it specializes on both backends.\n    var bobNext = ages[\"bob\"] + 1;\n    Console.println(\"bob next year={bobNext}\");\n\n    // Int-keyed map (Map<int, string>). An int-literal index interpolates directly.\n    Map<int, string> names = [1 => \"one\", 2 => \"two\", 3 => \"three\"];\n    Console.println(\"names[2]={names[2]} names[3]={names[3]}\");\n\n    // `var` infers the map type from the literal.\n    var caps = [\"fr\" => \"Paris\", \"jp\" => \"Tokyo\"];\n    var jp = caps[\"jp\"];\n    Console.println(\"jp capital={jp}\");\n}\n",
  "match-expr": "package Main;\nimport Core.Console;\n\n// `match` in EXPRESSION position (M11) — usable as a sub-expression, not only as a whole\n// `return`/`var =` statement. It transpiles to an immediately-invoked PHP closure wrapping the same\n// if-chain the statement form uses (so both positions share one lowering and stay byte-identical on\n// run/runvm/PHP). Literal patterns (`0 => …`) and a binding catch-all are exercised alongside.\n\nenum Color { Red, Green, Blue }\n\nfunction name(Color c) -> string {\n    // statement-position match (var-decl-init) over variant patterns\n    string n = match c { Red() => \"red\", Green() => \"green\", Blue() => \"blue\" };\n    return n;\n}\n\nfunction main() {\n    int base = 100;\n\n    // expression position: a match used as the left operand of `+`\n    int code = (match 2 { 1 => 10, 2 => 20, other => other }) + base;\n\n    // expression position: a match used as a call argument (its arms produce enum values)\n    string picked = name(match base { 100 => Blue(), x => Red() });\n\n    // literal-pattern match in return position, via a helper\n    Console.println(\"code={code} picked={picked} sign={sign(0)} sign2={sign(7)}\");\n}\n\nfunction sign(int n) -> string {\n    return match n { 0 => \"zero\", x => \"nonzero {x}\" };\n}\n",
  "math": "package Main;\nimport Core.Console;\nimport Core.Math;\n\n// M3 Track B Wave 2 — the `Core.Math` stdlib module. Each function erases to the PHP builtin of\n// the same name. Float ops (`sqrt`/`pow`/`floor`/`ceil`) return `float`; `abs`/`min`/`max` are\n// `int`. Every finite float renders byte-identically across all three backends (the transpiler's\n// `__phorge_float` helper reproduces Rust's shortest-round-trip `f64` Display) — see\n// `examples/guide/floats.phg` for the full magnitude/precision showcase.\n\nfunction main() {\n    // float math\n    float root = Math.sqrt(16.0);\n    float power = Math.pow(2.0, 10.0);\n    float down = Math.floor(3.7);\n    float up = Math.ceil(3.2);\n    Console.println(\"sqrt(16) = {root}, 2^10 = {power}, floor(3.7) = {down}, ceil(3.2) = {up}\");\n\n    // int math\n    int magnitude = Math.abs(-7);\n    int smaller = Math.min(3, 8);\n    int larger = Math.max(3, 8);\n    Console.println(\"abs(-7) = {magnitude}, min(3,8) = {smaller}, max(3,8) = {larger}\");\n\n    // round → int, half-away-from-zero (PHP's default mode), then a truncating cast.\n    int near = Math.round(2.5);\n    int far = Math.round(-2.5);\n    Console.println(\"round(2.5) = {near}, round(-2.5) = {far}\");\n}",
  "mutable-fields": "package Main;\nimport Core.Console;\n\n// M-mut.6 — shared-mutable instance fields: `o.f = e`. Instances are HANDLES (like PHP/Java\n// objects), not value types: two bindings to the same instance share one cell, so a write through\n// one is visible through the other. A field must be declared `mutable` to be assignable — every\n// field is immutable by default (the `mutable` opt-in mirrors `var` for locals).\n\nclass Counter {\n    // A `mutable` promoted field (assignable) and a declared `mutable` field set in the ctor body.\n    mutable int hits;\n    constructor(public mutable int n) {\n        this.hits = 0;\n    }\n    function bump() -> int {\n        this.n = this.n + 1;\n        this.hits = this.hits + 1;\n        return this.n;\n    }\n}\n\nfunction main() {\n    mutable Counter c = Counter(10);\n\n    // Direct field set.\n    c.n = 42;\n    Console.println(\"c.n = {c.n}\"); // 42\n\n    // HANDLE semantics: `alias` and `c` are the SAME instance — a write through one is seen by both\n    // (the opposite of the copy-on-write value types in element-set.phg).\n    Counter alias = c;\n    c.n = 100;\n    Console.println(\"c.n = {c.n}, alias.n = {alias.n}\"); // 100, 100\n\n    // A method mutating `this.f` is likewise visible everywhere.\n    c.bump();\n    c.bump();\n    Console.println(\"c.n = {c.n}, alias.n = {alias.n}, hits = {alias.hits}\"); // 102, 102, 2\n}\n",
  "mutable": "package Main;\nimport Core.Console;\n\n// M-mut.1 — mutable locals + reassignment.\n// Bindings are IMMUTABLE by default; only a `mutable` binding may be reassigned.\n\nfunction main() {\n    // A mutable counter, reassigned twice.\n    mutable int counter = 0;\n    counter = counter + 1;\n    counter = counter + 1;\n    Console.println(\"counter = {counter}\");\n\n    // `mutable var` infers its type from the initializer and is still reassignable.\n    mutable var total = 10;\n    total = total * 3;\n    Console.println(\"total = {total}\");\n\n    // Two-binding scalar case: scalars copy, so reassigning `b` leaves `a` untouched.\n    int a = 10;\n    mutable int b = a;\n    b = 99;\n    Console.println(\"a = {a} b = {b}\");\n\n    // Reassignment as a loop accumulator (the immutable `n` is a fresh binding each iteration).\n    mutable int sum = 0;\n    for (int n in 1..=5) {\n        sum = sum + n;\n    }\n    Console.println(\"sum 1..=5 = {sum}\");\n}\n",
  "null-safety": "package Main;\nimport Core.Console;\n\n// M3 S2 \"null safety\": optionals `T?`, `??`, `?.`, `if (var x = opt)`, `opt!`, and `match` over\n// `T?`. A non-optional `T` can never hold `null` — the checker enforces it (TypeScript\n// `strictNullChecks` over PHP's nullable runtime). These operators are the only ways from `T?` to T.\n\nclass Box {\n    constructor(private int v) {}\n    function get() -> int { return v; }\n}\n\n// `match` over an optional: the `null` arm handles absence; the binding arm narrows `v` to `int`.\nfunction describe(int? o) -> string {\n    return match o {\n        null => \"absent\",\n        v => \"present {v}\",\n    };\n}\n\nfunction main() {\n    // A `T?` holds a value or `null`; a non-optional `T` widens to `T?`.\n    int? some = 7;\n    int? none = null;\n\n    // `??` supplies a default when the left side is null (and skips it otherwise).\n    Console.println(\"coalesce: {some ?? -1} {none ?? -1}\");\n\n    // `?.` reads through a present receiver and short-circuits a null one to `null`.\n    Box? box = Box(42);\n    Box? nobox = null;\n    Console.println(\"safe: {(box?.get()) ?? -1} {(nobox?.get()) ?? -1}\");\n\n    // `if (var x = opt)` binds the non-null inner inside the then-block only (smart-cast to `int`).\n    if (var x = some) {\n        Console.println(\"if-let: got {x}\");\n    } else {\n        Console.println(\"if-let: none\");\n    }\n    if (var y = none) {\n        Console.println(\"if-let: got {y}\");\n    } else {\n        Console.println(\"if-let: none\");\n    }\n\n    // `opt!` force-unwraps a known-present optional to `int` (it would fault on null — never used on\n    // a value that can be null; the `W-FORCE-UNWRAP` lint flags every use). `x` is then a real `int`.\n    int forced = some!;\n    Console.println(\"force: {forced + 1}\");\n\n    // `match` over `T?` with null-arm narrowing.\n    Console.println(\"match: {describe(some)} / {describe(none)}\");\n}",
  "numeric": "// Numeric primitives — literal formats and bitwise operators (primitives P1 + P2).\n//\n// Number literals: decimal, hex `0x`, binary `0b`, octal `0o` (Rust-style — a leading `0` stays\n// decimal, no implicit-octal footgun), `_` digit separators, and `1e3` scientific floats. The literal's\n// VALUE (not its surface form) reaches the program, so every base collapses to the same int/float.\n//\n// Bitwise operators on `int`: `&` (and), `|` (or), `^` (xor), `~` (not), `<<` (shift-left),\n// `>>` (shift-right). PHP-identical integer semantics; a shift by a negative count faults. They are\n// int-only (a non-int operand is a compile error) and transpile 1:1 to PHP's native operators.\npackage Main;\nimport Core.Console;\n\nfunction main() {\n    // The same value written four ways.\n    int a = 255;\n    int b = 0xFF;\n    int c = 0b1111_1111;\n    int d = 0o377;\n    Console.println(\"{a} {b} {c} {d}\");\n\n    // Underscore separators read more clearly for large numbers.\n    int million = 1_000_000;\n    Console.println(\"{million}\");\n\n    // Bitwise: a flag set built and queried with masks.\n    int read = 0b001;\n    int write = 0b010;\n    int exec = 0b100;\n    int perms = read | write;\n    Console.println(\"{perms}\");                 // 3 (read+write)\n    Console.println(\"{perms & write}\");          // 2 (write bit is set)\n    Console.println(\"{perms & exec}\");           // 0 (exec bit is not)\n    Console.println(\"{perms ^ write}\");          // 1 (toggle write off)\n    Console.println(\"{perms << 1} {perms >> 1}\");// 6 1\n    Console.println(\"{~0}\");                     // -1 (all bits set)\n}\n",
  "operators": "package Main;\nimport Core.Console;\n\n// Arithmetic, comparison, logical, and unary operators.\n// Integer arithmetic is overflow-checked (a real overflow faults cleanly on both backends).\n\nfunction main() {\n    int a = 7;\n    int b = 3;\n    Console.println(\"a + b = {a + b}\");\n    Console.println(\"a - b = {a - b}\");\n    Console.println(\"a * b = {a * b}\");\n    Console.println(\"a / b = {a / b}\");   // integer division\n    Console.println(\"a % b = {a % b}\");\n\n    float x = 7.0;\n    float y = 2.0;\n    Console.println(\"x / y = {x / y}\");   // float division\n\n    Console.println(\"a < b   = {a < b}\");\n    Console.println(\"a == 7  = {a == 7}\");\n    Console.println(\"a != b  = {a != b}\");\n    Console.println(\"and     = {(a > b) && (x > y)}\");\n    Console.println(\"or      = {(a < b) || (x > y)}\");\n    Console.println(\"not     = {!(a < b)}\");\n    Console.println(\"neg     = {-a}\");\n}",
  "overloading": "package Main;\n\nimport Core.Console;\n\n// M-RT method & function overloading — DYNAMIC multiple dispatch. Several functions (or methods) may\n// share a name with distinct parameter signatures; the RUNTIME types of the arguments select the\n// most-specific matching overload. This is identical on the interpreter, the VM, and the transpiled\n// PHP (one `is_*`/`instanceof` dispatcher), so the program runs byte-identically on all three. All\n// overloads of a name share a return type (the call stays statically typed regardless of which fires).\n\n// Free-function overloads distinguished by parameter type (int / string / bool are runtime-disjoint).\nfunction describe(int n) -> string { return \"int {n}\"; }\nfunction describe(string s) -> string { return \"string \\\"{s}\\\"\"; }\nfunction describe(bool b) -> string { return \"bool {b}\"; }\n\n// Overloads distinguished by ARITY.\nfunction combine(int a) -> int { return a; }\nfunction combine(int a, int b) -> int { return a + b; }\nfunction combine(int a, int b, int c) -> int { return a + b + c; }\n\n// Class/interface overloads: a `Circle` value picks `area(Circle)` (most-specific); any other `Shape`\n// falls through to `area(Shape)`. The receiver's runtime type drives the choice, not the static type.\ninterface Shape {}\nclass Circle implements Shape { constructor(public int r) {} }\nclass Square implements Shape { constructor(public int side) {} }\n\nfunction area(Circle c) -> int { return c.r * c.r * 3; }\nfunction area(Shape s) -> int { return 0; }\n\n// Method overloading: the same dispatch over a class method (the `this` receiver is not part of it).\nclass Formatter {\n  constructor(public string sep) {}\n  function render(int n) -> string { return \"n{this.sep}{n}\"; }\n  function render(string s) -> string { return \"s{this.sep}{s}\"; }\n  function render(Circle c) -> string { return \"circle{this.sep}{c.r}\"; }\n}\n\nfunction main() {\n  Console.println(describe(42));\n  Console.println(describe(\"hi\"));\n  Console.println(describe(true));\n\n  Console.println(\"{combine(1)} {combine(1, 2)} {combine(1, 2, 3)}\");\n\n  Circle c = Circle(5);\n  Square q = Square(4);\n  Console.println(\"circle area = {area(c)}\");\n  Console.println(\"square area (Shape fallback) = {area(q)}\");\n\n  Formatter f = Formatter(\":\");\n  Console.println(f.render(7));\n  Console.println(f.render(\"tag\"));\n  Console.println(f.render(c));\n}\n",
  "pattern-matching": "// Match-arm guards — an optional `when <cond>` on a match arm (M-RT pattern cluster S5.1).\n//\n// A guard is an extra boolean condition on an arm: the arm matches only when the pattern matches AND\n// the guard holds. A false guard falls through to the next arm (arms are tried top-to-bottom,\n// first-match-wins), so several arms can share a shape with different conditions. Most arms have no\n// guard. The guard can read the arm's pattern bindings.\n//\n// A guarded arm does NOT discharge its shape for exhaustiveness (the guard might be false), so an\n// unguarded fallback for that shape is still required — here the final `Code(n) =>` and the unguarded\n// `Circle c =>`. Guards use a contextual `when` (a normal identifier elsewhere), lower to the existing\n// branch ops (no new VM op), and fold into the transpiled PHP if/elseif chain.\npackage Main;\nimport Core.Console;\n\nenum Status {\n    Code(int n)\n}\n\n// Several arms share the `Code` shape, separated by guards; the last is the unguarded fallback.\nfunction classify(Status s) -> string {\n    return match s {\n        Code(n) when n >= 500 => \"server error\",\n        Code(n) when n >= 400 => \"client error\",\n        Code(n) when n >= 200 => \"ok\",\n        Code(n) => \"informational ({n})\",\n    };\n}\n\nclass Circle {\n    constructor(public float r) {}\n}\n\nclass Square {\n    constructor(public float side) {}\n}\n\n// Guards on type-patterns over a union, reading a field in the guard condition.\nfunction describe(Circle | Square sh) -> string {\n    return match sh {\n        Circle c when c.r > 1.0 => \"big circle\",\n        Circle c => \"small circle\",\n        Square s => \"square\",\n    };\n}\n\nclass Point {\n    constructor(public int x, public int y) {}\n}\n\nclass Line {\n    constructor(public Point from, public Point to) {}\n}\n\n// Struct (named-field) destructuring (S5.2): bind a class instance's fields by name. Shorthand\n// `Circle { r }`, rename `Point { x: fx }`, and nesting `Line { from: Point { x, y }, to }` — the\n// same `instanceof` test as a type pattern (no new op), then field reads. Bound fields are usable as\n// typed values (here `fx + fy` as an `int` operand — the CTy operand path).\nfunction areaOf(Circle | Square sh) -> float {\n    return match sh {\n        Circle { r } => r,\n        Square { side } => side,\n    };\n}\n\nfunction originSum(Line l) -> int {\n    return match l {\n        Line { from: Point { x: fx, y: fy }, to } => fx + fy + to.x,\n        _ => 0,\n    };\n}\n\ninterface Animal {}\n\nclass Cat implements Animal {\n    constructor(public string name) {}\n}\n\nclass Dog implements Animal {\n    constructor(public string name) {}\n}\n\nenum Carrier {\n    Holds(Animal a)\n}\n\n// Nested type pattern inside a variant payload (S5.2): match the variant, then narrow its payload to\n// a concrete class in one pattern. A refutable payload (`Holds(Cat c)`) does not discharge the\n// `Holds` variant, so a `Holds(other)` binding (irrefutable) is the fallback.\nfunction speak(Carrier c) -> string {\n    return match c {\n        Holds(Cat cat) => \"meow from {cat.name}\",\n        Holds(Dog dog) => \"woof from {dog.name}\",\n        Holds(other) => \"...\",\n    };\n}\n\n// Flow-narrowing (S5.3): an early-return guard narrows the rest of the function. After\n// `if (!(sh instanceof Circle)) { return … }`, `sh` is a `Circle` for the remaining code — no cast,\n// no nested block. (Also: an `if (x instanceof T) {…} else {…}` narrows `x` to the remaining union\n// member in the else-branch.) Narrowing is a compile-time check — the runtime is unchanged.\nfunction radiusOrZero(Circle | Square sh) -> float {\n    if (!(sh instanceof Circle)) { return 0.0; }\n    return sh.r;\n}\n\nclass User {\n    constructor(public string name, public int age) {}\n}\n\nfunction lookup(int id) -> User? {\n    if (id == 1) { return User(\"Ada\", 36); }\n    if (id == 2) { return User(\"Bob\", 15); }\n    return null;\n}\n\n// if-let `when` guard (S5.3): bind an optional AND test a condition on the bound value in one\n// header. The then-branch runs only when the bind succeeds AND the guard holds; the else runs\n// otherwise (bind failed, or guard false). The guard can be a compound condition over the binding.\n// (`when` is contextual; this desugars to a nested `if` inside the bind's scope — no new VM op.)\nfunction greet(int id) -> string {\n    if (var u = lookup(id) when u.age >= 18 && u.name != \"\") {\n        return \"welcome {u.name}\";\n    } else {\n        return \"denied\";\n    }\n}\n\nfunction main() {\n    Console.println(classify(Code(503)));\n    Console.println(classify(Code(404)));\n    Console.println(classify(Code(200)));\n    Console.println(classify(Code(100)));\n    Console.println(describe(Circle(2.0)));\n    Console.println(describe(Circle(0.5)));\n    Console.println(describe(Square(3.0)));\n\n    // struct destructuring: shorthand, rename, nested\n    float ac = areaOf(Circle(2.5));\n    float aq = areaOf(Square(4.0));\n    int d = originSum(Line(Point(1, 2), Point(10, 20)));\n    Console.println(\"areaOf circle = {ac}, square = {aq}, origin sum = {d}\");\n\n    // nested type pattern in a variant payload\n    Console.println(speak(Holds(Cat(\"Tom\"))));\n    Console.println(speak(Holds(Dog(\"Rex\"))));\n\n    // if-let with a `when` guard\n    Console.println(greet(1));  // Ada, 36 → welcome\n    Console.println(greet(2));  // Bob, 15 → guard false → denied\n    Console.println(greet(3));  // null → bind fails → denied\n\n    // flow-narrowing (early-return guard)\n    float r = radiusOrZero(Circle(3.0));\n    float z = radiusOrZero(Square(5.0));\n    Console.println(\"r={r} z={z}\");\n}\n",
  "property-hooks": "package Main;\nimport Core.Console;\n\n// M-mut.7b — property hooks: a member that looks like a field but runs code on read (`get`) and/or\n// on write (`set`). A hook is *virtual* — it has no storage of its own; its body reads and writes\n// other (stored) fields. `get => expr` is a computed read; `set(T v) { … }` intercepts a write,\n// binding the assigned value to `v`. A hook may be read-only (get only), write-only (set only), or\n// both. It transpiles 1:1 to a PHP 8.4 property hook.\n\nclass Temp {\n    // One stored field; `fahrenheit` is a hook computed from it both ways.\n    constructor(public mutable float celsius) {}\n\n    float fahrenheit {\n        get => this.celsius * 9.0 / 5.0 + 32.0;\n        set(float f) { this.celsius = (f - 32.0) * 5.0 / 9.0; }\n    }\n}\n\nclass Account {\n    constructor(public mutable int raw) {}\n\n    // A write-validating hook: the `set` clamps negatives to zero before storing. A read-only\n    // computed hook (`isEmpty`) derives a boolean from the stored balance.\n    int balance {\n        get => this.raw;\n        set(int v) { if (v < 0) { this.raw = 0; } else { this.raw = v; } }\n    }\n\n    bool isEmpty {\n        get => this.raw == 0;\n    }\n}\n\nfunction main() {\n    Temp t = Temp(100.0);\n    Console.println(\"100C is {t.fahrenheit}F\"); // 100C is 212F\n    // Writing the hook converts back into the stored celsius field.\n    t.fahrenheit = 32.0;\n    Console.println(\"32F is {t.celsius}C\"); // 32F is 0C\n    // A computed read is a first-class operand.\n    Console.println(\"delta: {t.fahrenheit + 18.0}\"); // 32 + 18 = 50\n\n    Account a = Account(50);\n    Console.println(\"balance: {a.balance}, empty: {a.isEmpty}\"); // 50, false\n    a.balance = -10; // the set hook clamps to 0\n    Console.println(\"after -10: {a.balance}, empty: {a.isEmpty}\"); // 0, true\n}\n",
  "result": "// Error-as-value with `Result<T, E>` and the `?` propagation operator (M-faults Slice 2a).\n//\n// `Result<T, E>` is just the generic enum from M-RT — `Ok(T)` for success, `Err(E)` for failure. The\n// `?` operator is the ergonomic glue: in a let-initializer, `var x = mayFail()?;` unwraps an `Ok` to\n// its value, or **early-returns the `Err`** from the enclosing function (which must itself return a\n// `Result`). It turns a chain of fallible steps into straight-line code without a pyramid of `match`.\n//\n// `?` is allowed only as the whole initializer of a binding (`int a = f()?;`). Anywhere else — nested\n// in a larger expression like `g(f()?)`, or a `return f()?;` — is a compile error (`E-PROPAGATE-POSITION`):\n// bind the result to a local first. On the two Phorge backends `?` early-returns mid-expression\n// directly; transpiled to PHP it lowers to `$t = f(); if ($t instanceof Err) return $t; $x = $t->value;`\n// — byte-identical output on `run`, `runvm`, and real PHP.\n\npackage Main;\n\nimport Core.Console;\n\nenum Result<T, E> {\n    Ok(T value),\n    Err(E error),\n}\n\n// Parse a small \"config\" of two integer fields. Each lookup may fail; `?` propagates the first failure.\nfunction field(int key) -> Result<int, string> {\n    if (key < 0) {\n        return Err(\"negative key {key}\");\n    }\n    return Ok(key * 10);\n}\n\n// Straight-line happy path: every `?` either unwraps or short-circuits the whole function to its `Err`.\nfunction combine(int a, int b) -> Result<int, string> {\n    int x = field(a)?; // unwrap or early-return Err\n    int y = field(b)?;\n    return Ok(x + y);\n}\n\nfunction show(Result<int, string> r) -> string {\n    return match r {\n        Ok(v) => \"ok {v}\",\n        Err(e) => \"err {e}\",\n    };\n}\n\n// The third tier is *unchecked faults / panics* — for programmer bugs, never declared up the chain.\n// `panic(\"msg\")`, `todo()`, and `unreachable()` are `never`-typed (they satisfy return-on-all-paths and\n// crash with a stack trace); `assert(cond[, \"msg\"])` faults only when its condition is false. Because a\n// fault crashes, panics can't appear in a *runnable* example — but a *passing* `assert` runs cleanly and\n// is byte-identical, so we show that form here. (A failing `panic`/`assert` transpiles to a PHP `throw`.)\n\nfunction main() {\n    assert(1 < 2, \"arithmetic is intact\"); // passes — a no-op; a false condition would fault\n    Console.println(show(combine(1, 2))); // ok 30   — both fields succeed (10 + 20)\n    Console.println(show(combine(3, -1))); // err negative key -1 — second field fails, `?` short-circuits\n    Console.println(show(combine(-5, 9))); // err negative key -5 — first field fails\n}\n",
  "sets": "// Core.Set (M-RT S7b) — a generic set built from a list. `Set.of(List<T>) -> Set<T>` deduplicates\n// preserving first-occurrence order; `Set.contains(Set<T>, T) -> bool` and `Set.size(Set<T>) -> int`\n// query it. Like Map, a Set is insertion-ordered (not a HashSet) so it round-trips byte-identically\n// through PHP (a deduped array): run / runvm / real PHP all agree.\n//\n// Elements are the hashable subset (int / bool / string). The example uses int and string sets;\n// dedup matches PHP `array_unique(..., SORT_STRING)` for homogeneous element types.\npackage Main;\n\nimport Core.Console;\nimport Core.Set;\n\nfunction main() {\n    // An int set, built from a list with duplicates → deduped, first-occurrence order preserved.\n    var s = Set.of([3, 1, 4, 1, 5, 9, 2, 6, 5, 3]);\n    var has4 = Set.contains(s, 4);\n    var has7 = Set.contains(s, 7);\n    Console.println(\"size  = {Set.size(s)}\");\n    Console.println(\"has 4 = {has4}\");\n    Console.println(\"has 7 = {has7}\");\n\n    // A string set — same ops, different element type (generics inferred at the call site).\n    var names = Set.of([\"ada\", \"bob\", \"ada\", \"cleo\", \"bob\"]);\n    var hasAda = Set.contains(names, \"ada\");\n    var hasZoe = Set.contains(names, \"zoe\");\n    Console.println(\"names size = {Set.size(names)}\");\n    Console.println(\"has ada    = {hasAda}\");\n    Console.println(\"has zoe    = {hasZoe}\");\n}\n",
  "static-fields": "package Main;\nimport Core.Console;\n\n// M-mut.7 — `static` class fields: program-lifetime state that belongs to the class, not to any one\n// instance. Accessed as `ClassName.field` (Phorge uses `.` everywhere, not `::`). A static field is\n// immutable by default; `static mutable` opts into reassignment. Static initializers are literal\n// constants, evaluated once at program start.\n\nclass Counter {\n    // One slot shared by every Counter — the constructor bumps it, so it counts all instances ever\n    // created. `label` is an immutable static (a class-level constant).\n    static mutable int total = 0;\n    static string label = \"counters created\";\n\n    constructor() {\n        Counter.total = Counter.total + 1;\n    }\n}\n\nfunction main() {\n    Counter();\n    Counter();\n    Counter();\n    // Read the shared state through the class name — no instance needed.\n    Console.println(\"{Counter.label}: {Counter.total}\"); // counters created: 3\n\n    // A static is also writable directly (when `mutable`), and reads as an arithmetic operand.\n    Counter.total = Counter.total + 10;\n    Console.println(\"after +10: {Counter.total}\"); // after +10: 13\n}\n",
  "strings": "package Main;\nimport Core.Console;\n\nfunction greet(string who) -> string {\n    return \"Hello, {who}!\";\n}\n\nfunction main() {\n    string name = \"Phorge\";\n    int n = 3;\n    float pi = 3.14;\n    Console.println(\"name = {name}, n = {n}, pi = {pi}\");\n    Console.println(\"n + 1 = {n + 1}\");\n    Console.println(greet(name));\n\n    // bind first — the interpolation sub-lexer does not nest string literals inside {…}\n    string w = \"world\";\n    Console.println(\"nested call: {greet(w)}\");\n}",
  "text": "package Main;\nimport Core.Console;\nimport Core.Text;\n\n// M3 Track B Wave 2 — the `Core.Text` stdlib module. Each function erases to a PHP string builtin\n// (`strlen`/`strtoupper`/`explode`/`implode`/`strReplace`/…). ASCII text keeps the Rust backends\n// and PHP byte-identical (`len` is the byte length; `upper`/`lower` are ASCII-case).\n//\n// Note: bind call results to locals before interpolating — the interpolation sub-lexer does not\n// nest string literals inside `{…}` (same constraint as guide/strings.phg).\n\nfunction main() {\n    string greeting = \"Hello, Phorge\";\n\n    int n = Text.len(greeting);\n    string up = Text.upper(greeting);\n    string down = Text.lower(greeting);\n    string padded = Text.trim(\"   padded   \");\n    Console.println(\"len = {n}, upper = {up}, lower = {down}, trimmed = {padded}\");\n\n    // `contains` returns a bool; render it through an expression-`if` so the output is a string.\n    string has = if (Text.contains(greeting, \"Phorge\")) { \"yes\" } else { \"no\" };\n    Console.println(\"contains 'Phorge' = {has}\");\n\n    // split → List<string>, then join with a different separator (the inverse op).\n    List<string> parts = Text.split(\"a,b,c\", \",\");\n    string rejoined = Text.join(parts, \" - \");\n    Console.println(\"rejoined = {rejoined}\");\n\n    string swapped = Text.replace(greeting, \"Phorge\", \"World\");\n    Console.println(\"replaced = {swapped}\");\n\n    // P3.2 byte-safe subset: prefix/suffix tests (→ str_starts_with/str_ends_with) and repeat\n    // (→ str_repeat). Bool results render via expression-`if` (PHP echoes a bool as 1/\"\").\n    string sw = if (Text.startsWith(greeting, \"Hello\")) { \"yes\" } else { \"no\" };\n    string ew = if (Text.endsWith(greeting, \"Phorge\")) { \"yes\" } else { \"no\" };\n    string bar = Text.repeat(\"=\", 5);\n    Console.println(\"startsWith 'Hello' = {sw}, endsWith 'Phorge' = {ew}, bar = {bar}\");\n}",
  "totality": "// Totality — return-on-all-paths, the `never` bottom type, and dead-code lints (M-RT totality cluster).\n//\n// A function whose return type carries a value must `return` (or diverge) on EVERY path — Phorge\n// rejects a typed function that can fall off the end (`E-MISSING-RETURN`), closing the type system's\n// #1 soundness leak. `never` is the bottom type: a `-> never` function is verified to never return\n// (today, via an infinite loop). Unreachable code after a `return`, and a `match` arm after a\n// catch-all, are flagged as non-fatal warnings. All of this is checker-only — it transpiles 1:1 to\n// PHP (`never` → PHP 8.1 native `never`) and runs byte-identically on both backends.\npackage Main;\n\nimport Core.Console;\n\n// Every branch returns — total over all paths (an `if`/`else if`/`else` chain).\nfunction classify(int score) -> string {\n    if (score >= 90) {\n        return \"A\";\n    } else if (score >= 60) {\n        return \"pass\";\n    } else {\n        return \"fail\";\n    }\n}\n\n// An expression `if` in value position returns via BOTH arms — also total.\nfunction larger(int a, int b) -> int {\n    return if (a > b) { a } else { b };\n}\n\n// A `match` that returns on every arm is total (the arms are exhaustive over `int` via `_`).\nfunction sign(int n) -> string {\n    return match n {\n        0 => \"zero\",\n        _ => if (n > 0) { \"positive\" } else { \"negative\" },\n    };\n}\n\n// The bottom type: a `-> never` function provably diverges, so it never returns a value. Declared to\n// showcase the type (and its PHP `: never` hint); never called, so the program still terminates.\nfunction spinForever() -> never {\n    while (true) {}\n}\n\nfunction main() {\n    Console.println(classify(95));\n    Console.println(classify(75));\n    Console.println(classify(40));\n    Console.println(\"larger = {larger(3, 8)}\");\n    Console.println(sign(0));\n    Console.println(sign(7));\n    Console.println(sign(-2));\n}\n",
  "traits": "// Traits — horizontal code reuse with `trait` / `use` (Rich Types — M-RT S8).\n//\n// A trait is a reusable bundle of behavior and state that a class composes with `use`. Unlike a\n// parent class (`extends`), a trait is NOT a type: you cannot type a value as a trait, and\n// `instanceof Trait` is rejected — `extends` means *is-a*, `use` means *has-the-behavior-of*. A\n// trait may carry methods (any visibility), instance + `static` state, a constructor, an `abstract`\n// requirement the using class must satisfy, and property hooks. Trait members flatten into the using\n// class before any backend runs, so the interpreter and VM see ordinary members; the transpiler emits\n// a native PHP `trait` + `use`. Every backend (interpreter, VM, real PHP) agrees byte-for-byte.\npackage Main;\n\nimport Core.Console;\n\n// Method reuse, including a `private` helper only other trait methods can call.\ntrait Loud {\n    private function emphasize(string s) -> string {\n        return \"{s}!\";\n    }\n    function shout(string s) -> string {\n        return this.emphasize(s);\n    }\n}\n\n// State: a `mutable` field plus a constructor that derives it (promotion + a body). A class composing\n// this trait and declaring no constructor of its own adopts this one.\ntrait Paid {\n    mutable int annual;\n    constructor(int monthly) {\n        this.annual = monthly * 12;\n    }\n    function raise(int pct) {\n        this.annual = this.annual + this.annual * pct / 100;\n    }\n}\n\n// An `abstract` requirement the using class must satisfy, and a get-hook that reads it.\ntrait Identified {\n    abstract function id() -> int;\n    string badge {\n        get => \"#{this.id()}\";\n    }\n}\n\n// A `static` field — each using class gets its own copy (PHP `use` semantics).\ntrait Counted {\n    static mutable int created = 0;\n}\n\n// Compose several traits at once. `Employee` provides the `id` the `Identified` trait requires.\nclass Employee {\n    use Loud;\n    use Paid;\n    use Identified;\n    use Counted;\n\n    function id() -> int {\n        return 7;\n    }\n}\n\nfunction main() {\n    Employee e = Employee(1000); // Paid's constructor runs: annual = 1000 * 12 = 12000\n    e.raise(10); // 12000 + 10% = 13200\n\n    Console.println(e.shout(\"hello\")); // Loud: hello!\n    Console.println(\"{e.annual}\"); // Paid state, mutated: 13200\n    Console.println(e.badge); // Identified hook reading the abstract id(): #7\n\n    Employee.created = 3;\n    Console.println(\"{Employee.created}\"); // Counted static: 3\n}\n",
  "unions": "// Union types `A | B | C` — the open-composition counterpart to a closed `enum` (M-RT S4).\n//\n// A union value is *one of* several types. Members may be classes, interfaces, or primitives, and a\n// value of any member flows into a union-typed slot (`Circle` → `Circle | Square | Triangle`). You\n// reach a member's data two ways:\n//   • match-over-union with **type patterns** — `match s { Circle c => … }` (exhaustive over the\n//     member set, like an enum match), each arm binding the narrowed value;\n//   • `instanceof` narrowing in an `if` — `if (s instanceof Circle) { … s.radius … }`.\n// Primitive unions (`int | string`) accept either type and match by literal value. Transpiles to\n// PHP 8.0 native `A|B`.\npackage Main;\nimport Core.Console;\n\nclass Circle {\n    constructor(public int radius) {}\n}\n\nclass Square {\n    constructor(public int side) {}\n}\n\nclass Triangle {\n    constructor(public int base, public int height) {}\n}\n\n// match-over-union: one arm per member, each binding the narrowed instance. Exhaustive — no `_`\n// needed, exactly like an enum match.\nfunction area(Circle | Square | Triangle s) -> int {\n    return match s {\n        Circle c => c.radius * c.radius,\n        Square sq => sq.side * sq.side,\n        Triangle t => t.base * t.height,\n    };\n}\n\n// instanceof narrowing on a union operand: each `if` smart-casts `s` to the tested class in its body.\nfunction name(Circle | Square | Triangle s) -> string {\n    if (s instanceof Circle) {\n        return \"circle r={s.radius}\";\n    }\n    if (s instanceof Square) {\n        return \"square s={s.side}\";\n    }\n    return \"triangle\";\n}\n\n// A primitive union accepts either type; literal patterns match by value, with a `_` for the rest.\nfunction classify(int | string code) -> string {\n    return match code {\n        0 => \"zero\",\n        \"ok\" => \"okay\",\n        _ => \"other\",\n    };\n}\n\nfunction main() {\n    Circle c = Circle(2);\n    Square s = Square(3);\n    Triangle t = Triangle(4, 3);\n\n    Console.println(\"area circle = {area(c)}\");     // 4\n    Console.println(\"area square = {area(s)}\");     // 9\n    Console.println(\"area triangle = {area(t)}\");   // 12\n\n    Console.println(name(c));                        // circle r=2\n    Console.println(name(s));                        // square s=3\n    Console.println(name(t));                        // triangle\n\n    string okay = classify(\"ok\");\n    Console.println(\"classify 0 = {classify(0)}\"); // zero\n    Console.println(\"classify ok = {okay}\");        // okay\n    Console.println(\"classify 7 = {classify(7)}\"); // other\n}\n"
};
